// Type declarations for pdfjs-dist worker modules

declare module "pdfjs-dist/legacy/build/pdf.worker.mjs" {
  // Worker module has no exports, it's loaded for side effects
  export {};
}

declare module "pdfjs-dist/legacy/build/pdf.worker.min.mjs" {
  // Worker module has no exports, it's loaded for side effects
  export {};
}
